code = """import json
import os

# Load the 35 paper titles from 2016 physical activity domain
paper_path = locals().get('var_functions.query_db:2', '')
with open(paper_path, 'r') as f:
    papers = json.load(f)

titles_2016_pa = []
for paper in papers:
    filename = paper.get('filename', '')
    title = filename.replace('.txt', '') if filename else ''
    text = paper.get('text', '')
    
    if '2016' in text and 'physical activity' in text.lower() and title:
        titles_2016_pa.append(title)

# Load all citation data
citation_path = locals().get('var_functions.query_db:22', '')
with open(citation_path, 'r') as f:
    citations = json.load(f)

# Create dictionary to sum citations per title
citation_sums = {}
for record in citations:
    title = record.get('title', '')
    count = int(record.get('citation_count', 0))
    if title in citation_sums:
        citation_sums[title] += count
    else:
        citation_sums[title] = count

# Match papers with their citation counts
results = []
for title in titles_2016_pa:
    total_citations = citation_sums.get(title, 0)
    results.append({
        'title': title,
        'total_citations': total_citations
    })

# Sort by citation count descending
results.sort(key=lambda x: x['total_citations'], reverse=True)

print(f"Found {len(results)} papers")
print("\nTop 5 papers by citations:")
for i, paper in enumerate(results[:5], 1):
    print(f"{i}. {paper['title']}")
    print(f"   Total citations: {paper['total_citations']}")

print('__RESULT__:')
print(json.dumps({'papers': results, 'total_count': len(results)}))"""

